107: // Delays and aborts are independent events. One can inject a delay
108: // followed by an abort or inject just a delay or abort. In this callback,
109: // if we inject a delay, then we will inject the abort in the delay timer
110: // callback.
111: Http::FilterHeadersStatus FaultFilter::decodeHeaders(Http::RequestHeaderMap& headers, bool) {
112:   // Route-level configuration overrides filter-level configuration
113:   // NOTE: We should not use runtime when reading from route-level
114:   // faults. In other words, runtime is supported only when faults are
115:   // configured at the filter level.
116:   fault_settings_ = config_->settings();
117:   const auto* per_route_settings =
118:       Http::Utility::resolveMostSpecificPerFilterConfig<FaultSettings>(decoder_callbacks_);
119:   fault_settings_ = per_route_settings ? per_route_settings : fault_settings_;
120: 
121:   if (!matchesTargetUpstreamCluster()) {
122:     return Http::FilterHeadersStatus::Continue;
123:   }
124: 
125:   if (!matchesDownstreamNodes(headers)) {
126:     return Http::FilterHeadersStatus::Continue;
127:   }
128: 
129:   // Check for header matches
130:   if (!Http::HeaderUtility::matchHeaders(headers, fault_settings_->filterHeaders())) {
131:     return Http::FilterHeadersStatus::Continue;
132:   }
133: 
134:   if (headers.EnvoyDownstreamServiceCluster()) {
135:     downstream_cluster_ = std::string(headers.getEnvoyDownstreamServiceClusterValue());
136:     if (!downstream_cluster_.empty() && !fault_settings_->disableDownstreamClusterStats()) {
137:       downstream_cluster_storage_ = std::make_unique<Stats::StatNameDynamicStorage>(
138:           downstream_cluster_, config_->scope().symbolTable());
139:     }
140: 
141:     downstream_cluster_delay_percent_key_ =
142:         fmt::format("fault.http.{}.delay.fixed_delay_percent", downstream_cluster_);
143:     downstream_cluster_abort_percent_key_ =
144:         fmt::format("fault.http.{}.abort.abort_percent", downstream_cluster_);
145:     downstream_cluster_delay_duration_key_ =
146:         fmt::format("fault.http.{}.delay.fixed_duration_ms", downstream_cluster_);
147:     downstream_cluster_abort_http_status_key_ =
148:         fmt::format("fault.http.{}.abort.http_status", downstream_cluster_);
149:     downstream_cluster_abort_grpc_status_key_ =
150:         fmt::format("fault.http.{}.abort.grpc_status", downstream_cluster_);
151:   }
152: 
153:   maybeSetupResponseRateLimit(headers);
154: 
155:   if (maybeSetupDelay(headers)) {
156:     return Http::FilterHeadersStatus::StopIteration;
157:   }
158: 
159:   if (maybeDoAbort(headers)) {
160:     return Http::FilterHeadersStatus::StopIteration;
161:   }
162: 
163:   return Http::FilterHeadersStatus::Continue;
164: }
