166: bool FaultFilter::maybeSetupDelay(const Http::RequestHeaderMap& request_headers) {
167:   absl::optional<std::chrono::milliseconds> duration = delayDuration(request_headers);
168:   if (duration.has_value() && tryIncActiveFaults()) {
169:     delay_timer_ = decoder_callbacks_->dispatcher().createTimer(
170:         [this, &request_headers]() -> void { postDelayInjection(request_headers); });
171:     ENVOY_LOG(debug, "fault: delaying request {}ms", duration.value().count());
172:     delay_timer_->enableTimer(duration.value(), &decoder_callbacks_->scope());
173:     recordDelaysInjectedStats();
174:     decoder_callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::DelayInjected);
175:     auto& dynamic_metadata = decoder_callbacks_->streamInfo().dynamicMetadata();
176:     (*dynamic_metadata.mutable_filter_metadata())[decoder_callbacks_->filterConfigName()] =
177:         fault_settings_->filterMetadata();
178:     return true;
179:   }
180:   return false;
181: }
182: 
183: bool FaultFilter::maybeDoAbort(const Http::RequestHeaderMap& request_headers) {
184:   absl::optional<Http::Code> http_status;
185:   absl::optional<Grpc::Status::GrpcStatus> grpc_status;
186:   std::tie(http_status, grpc_status) = abortStatus(request_headers);
187: 
188:   if (http_status.has_value() && tryIncActiveFaults()) {
189:     abortWithStatus(http_status.value(), grpc_status);
190:     return true;
191:   }
192: 
193:   return false;
194: }
