175: void Filter::initiateCall(const Http::RequestHeaderMap& headers) {
176:   if (filter_return_ == FilterReturn::StopDecoding) {
177:     return;
178:   }
179: 
180:   // Now that we'll definitely be making the request, add filter state stats if configured to do so.
181:   const Envoy::StreamInfo::FilterStateSharedPtr& filter_state =
182:       decoder_callbacks_->streamInfo().filterState();
183:   if ((config_->emitFilterStateStats() || config_->filterMetadata().has_value())) {
184:     if (!filter_state->hasData<ExtAuthzLoggingInfo>(decoder_callbacks_->filterConfigName())) {
185:       filter_state->setData(decoder_callbacks_->filterConfigName(),
186:                             std::make_shared<ExtAuthzLoggingInfo>(config_->filterMetadata()),
187:                             Envoy::StreamInfo::FilterState::StateType::Mutable,
188:                             Envoy::StreamInfo::FilterState::LifeSpan::Request);
189: 
190:       // This may return nullptr (if there's a value at this name whose type doesn't match or isn't
191:       // mutable, for example), so we must check logging_info_ is not nullptr later.
192:       logging_info_ =
193:           filter_state->getDataMutable<ExtAuthzLoggingInfo>(decoder_callbacks_->filterConfigName());
194:     }
195:     if (logging_info_ == nullptr) {
196:       stats_.filter_state_name_collision_.inc();
197:       ENVOY_STREAM_LOG(debug,
198:                        "Could not find logging info at {}! (Did another filter already put data "
199:                        "at this name?)",
200:                        *decoder_callbacks_, decoder_callbacks_->filterConfigName());
201:     }
202:   }
203: 
204:   absl::optional<FilterConfigPerRoute> maybe_merged_per_route_config;
205:   for (const FilterConfigPerRoute& cfg :
206:        Http::Utility::getAllPerFilterConfig<FilterConfigPerRoute>(decoder_callbacks_)) {
207:     if (maybe_merged_per_route_config.has_value()) {
208:       maybe_merged_per_route_config.value().merge(cfg);
209:     } else {
210:       maybe_merged_per_route_config = cfg;
211:     }
212:   }
213: 
214:   Protobuf::Map<std::string, std::string> context_extensions;
215:   if (maybe_merged_per_route_config) {
216:     context_extensions = maybe_merged_per_route_config.value().takeContextExtensions();
217:   }
218: 
219:   // If metadata_context_namespaces or typed_metadata_context_namespaces is specified,
220:   // pass matching filter metadata to the ext_authz service.
221:   // If metadata key is set in both the connection and request metadata,
222:   // then the value will be the request metadata value.
223:   envoy::config::core::v3::Metadata metadata_context;
224:   fillMetadataContext({&decoder_callbacks_->streamInfo().dynamicMetadata(),
225:                        &decoder_callbacks_->connection()->streamInfo().dynamicMetadata()},
226:                       config_->metadataContextNamespaces(),
227:                       config_->typedMetadataContextNamespaces(), metadata_context);
228: 
229:   // Fill route_metadata_context from the selected route's metadata.
230:   envoy::config::core::v3::Metadata route_metadata_context;
231:   if (decoder_callbacks_->route() != nullptr) {
232:     fillMetadataContext({&decoder_callbacks_->route()->metadata()},
233:                         config_->routeMetadataContextNamespaces(),
234:                         config_->routeTypedMetadataContextNamespaces(), route_metadata_context);
235:   }
236: 
237:   Filters::Common::ExtAuthz::CheckRequestUtils::createHttpCheck(
238:       decoder_callbacks_, headers, std::move(context_extensions), std::move(metadata_context),
239:       std::move(route_metadata_context), check_request_, max_request_bytes_, config_->packAsBytes(),
240:       config_->headersAsBytes(), config_->includePeerCertificate(), config_->includeTLSSession(),
241:       config_->destinationLabels(), config_->allowedHeadersMatcher(),
242:       config_->disallowedHeadersMatcher());
243: 
244:   ENVOY_STREAM_LOG(trace, "ext_authz filter calling authorization server", *decoder_callbacks_);
245:   // Store start time of ext_authz filter call
246:   start_time_ = decoder_callbacks_->dispatcher().timeSource().monotonicTime();
247: 
248:   state_ = State::Calling;
249:   filter_return_ = FilterReturn::StopDecoding; // Don't let the filter chain continue as we are
250:                                                // going to invoke check call.
251:   cluster_ = decoder_callbacks_->clusterInfo();
252:   initiating_call_ = true;
253:   client_->check(*this, check_request_, decoder_callbacks_->activeSpan(),
254:                  decoder_callbacks_->streamInfo());
255:   initiating_call_ = false;
256: }
