660:     if (!response->response_headers_to_add_if_absent.empty()) {
661:       ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to add to the response:",
662:                        *decoder_callbacks_, response->response_headers_to_add_if_absent.size());
663:       for (const auto& [key, value] : response->response_headers_to_add_if_absent) {
664:         if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
665:                                              !Http::HeaderUtility::headerValueIsValid(value))) {
666:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
667:                            value);
668:           rejectResponse();
669:           return;
670:         }
671:       }
672:       response_headers_to_add_if_absent_ =
673:           Http::HeaderVector{response->response_headers_to_add_if_absent.begin(),
674:                              response->response_headers_to_add_if_absent.end()};
675:     }
676: 
677:     if (!response->response_headers_to_overwrite_if_exists.empty()) {
678:       ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to set to the response:",
679:                        *decoder_callbacks_,
680:                        response->response_headers_to_overwrite_if_exists.size());
681:       for (const auto& [key, value] : response->response_headers_to_overwrite_if_exists) {
682:         if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
683:                                              !Http::HeaderUtility::headerValueIsValid(value))) {
684:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
685:                            value);
686:           rejectResponse();
687:           return;
688:         }
689:       }
690:       response_headers_to_overwrite_if_exists_ =
691:           Http::HeaderVector{response->response_headers_to_overwrite_if_exists.begin(),
692:                              response->response_headers_to_overwrite_if_exists.end()};
693:     }
694: 
695:     absl::optional<Http::Utility::QueryParamsMulti> modified_query_parameters;
696:     if (!response->query_parameters_to_set.empty()) {
697:       modified_query_parameters = Http::Utility::QueryParamsMulti::parseQueryString(
698:           request_headers_->Path()->value().getStringView());
699:       ENVOY_STREAM_LOG(
700:           trace, "ext_authz filter set query parameter(s) on the request:", *decoder_callbacks_);
