703:             (!Http::Utility::PercentEncoding::queryParameterIsUrlEncoded(key) ||
704:              !Http::Utility::PercentEncoding::queryParameterIsUrlEncoded(value))) {
705:           ENVOY_STREAM_LOG(trace, "Rejected invalid query parameter {}={}.", *decoder_callbacks_,
706:                            key, value);
707:           rejectResponse();
708:           return;
709:         }
710:         ENVOY_STREAM_LOG(trace, "'{}={}'", *decoder_callbacks_, key, value);
711:         modified_query_parameters->overwrite(key, value);
712:       }
713:     }
714: 
715:     if (!response->query_parameters_to_remove.empty()) {
716:       if (!modified_query_parameters) {
717:         modified_query_parameters = Http::Utility::QueryParamsMulti::parseQueryString(
718:             request_headers_->Path()->value().getStringView());
719:       }
720:       ENVOY_STREAM_LOG(trace, "ext_authz filter removed query parameter(s) from the request:",
721:                        *decoder_callbacks_);
722:       for (const auto& key : response->query_parameters_to_remove) {
723:         ENVOY_STREAM_LOG(trace, "'{}'", *decoder_callbacks_, key);
