735:           *decoder_callbacks_, new_path);
736:       request_headers_->setPath(new_path);
737:     }
738: 
739:     if (cluster_) {
740:       config_->incCounter(cluster_->statsScope(), config_->ext_authz_ok_);
741:     }
742:     stats_.ok_.inc();
743:     continueDecoding();
744:     break;
745:   }
746: 
747:   case CheckStatus::Denied: {
748:     ENVOY_STREAM_LOG(trace, "ext_authz filter rejected the request. Response status code: '{}'",
749:                      *decoder_callbacks_, enumToInt(response->status_code));
750:     stats_.denied_.inc();
751: 
752:     if (cluster_) {
753:       config_->incCounter(cluster_->statsScope(), config_->ext_authz_denied_);
754:       if (config_->chargeClusterResponseStats()) {
755:         Http::CodeStats::ResponseStatInfo info{config_->scope(),
756:                                                cluster_->statsScope(),
757:                                                empty_stat_name,
758:                                                enumToInt(response->status_code),
759:                                                true,
760:                                                empty_stat_name,
761:                                                empty_stat_name,
762:                                                empty_stat_name,
763:                                                empty_stat_name,
764:                                                empty_stat_name,
765:                                                false};
766:         config_->httpContext().codeStats().chargeResponseStat(info, false);
767:       }
768:     }
769: 
770:     // Check headers are valid.
771:     if (config_->validateMutations()) {
772:       for (const auto& [key, value] : response->headers_to_set) {
773:         if (!Http::HeaderUtility::headerNameIsValid(key) ||
774:             !Http::HeaderUtility::headerValueIsValid(value)) {
775:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
776:                            value);
777:           rejectResponse();
778:           return;
779:         }
780:       }
781:     }
782: 
783:     // setResponseFlag must be called before sendLocalReply
784:     decoder_callbacks_->streamInfo().setResponseFlag(
785:         StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
786:     decoder_callbacks_->sendLocalReply(
787:         response->status_code, response->body,
788:         [&headers = response->headers_to_set,
789:          &callbacks = *decoder_callbacks_](Http::HeaderMap& response_headers) -> void {
790:           ENVOY_STREAM_LOG(trace,
791:                            "ext_authz filter added header(s) to the local response:", callbacks);
792:           // Firstly, remove all headers requested by the ext_authz filter, to ensure that they will
793:           // override existing headers.
794:           for (const auto& [key, _] : headers) {
795:             response_headers.remove(Http::LowerCaseString(key));
796:           }
797:           // Then set all of the requested headers, allowing the same header to be set multiple
798:           // times, e.g. `Set-Cookie`.
799:           for (const auto& [key, value] : headers) {
800:             ENVOY_STREAM_LOG(trace, " '{}':'{}'", callbacks, key, value);
801:             response_headers.addCopy(Http::LowerCaseString(key), value);
802:           }
803:         },
804:         absl::nullopt, Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzDenied);
805:     break;
806:   }
807: 
808:   case CheckStatus::Error: {
809:     if (cluster_) {
810:       config_->incCounter(cluster_->statsScope(), config_->ext_authz_error_);
811:     }
812:     stats_.error_.inc();
813:     if (config_->failureModeAllow()) {
814:       ENVOY_STREAM_LOG(trace, "ext_authz filter allowed the request with error",
815:                        *decoder_callbacks_);
816:       stats_.failure_mode_allowed_.inc();
817:       if (cluster_) {
818:         config_->incCounter(cluster_->statsScope(), config_->ext_authz_failure_mode_allowed_);
819:       }
820:       if (config_->failureModeAllowHeaderAdd()) {
821:         request_headers_->addReferenceKey(
822:             Filters::Common::ExtAuthz::Headers::get().EnvoyAuthFailureModeAllowed, "true");
823:       }
824:       continueDecoding();
825:     } else {
826:       ENVOY_STREAM_LOG(
827:           trace, "ext_authz filter rejected the request with an error. Response status code: {}",
828:           *decoder_callbacks_, enumToInt(config_->statusOnError()));
829:       decoder_callbacks_->streamInfo().setResponseFlag(
830:           StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
831:       decoder_callbacks_->sendLocalReply(
832:           config_->statusOnError(), EMPTY_STRING, nullptr, absl::nullopt,
833:           Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzError);
834:     }
835:     break;
836:   }
837:   }
838: }
