72: HeaderUtility::getAllOfHeaderAsString(const HeaderMap& headers, const Http::LowerCaseString& key,
73:                                       absl::string_view separator) {
74:   GetAllOfHeaderAsStringResult result;
75:   const auto header_value = headers.get(key);
76: 
77:   if (header_value.empty()) {
78:     // Empty for clarity. Avoid handling the empty case in the block below if the runtime feature
79:     // is disabled.
80:   } else if (header_value.size() == 1) {
81:     result.result_ = header_value[0]->value().getStringView();
82:   } else {
83:     return getAllOfHeaderAsString(header_value, separator);
84:   }
85: 
