397: absl::optional<uint32_t> HeaderUtility::stripPortFromHost(RequestHeaderMap& headers,
398:                                                           absl::optional<uint32_t> listener_port) {
399:   const absl::string_view original_host = headers.getHostValue();
400:   const absl::string_view::size_type port_start = getPortStart(original_host);
401:   if (port_start == absl::string_view::npos) {
402:     return absl::nullopt;
403:   }
404:   const absl::string_view port_str = original_host.substr(port_start + 1);
405:   uint32_t port = 0;
406:   if (!absl::SimpleAtoi(port_str, &port)) {
407:     return absl::nullopt;
408:   }
409:   if (listener_port.has_value() && port != listener_port) {
410:     // We would strip ports only if it is specified and they are the same, as local port of the
411:     // listener.
412:     return absl::nullopt;
413:   }
414:   const absl::string_view host = original_host.substr(0, port_start);
415:   headers.setHost(host);
416:   return port;
417: }
