113: bool ActiveStreamFilterBase::commonHandleAfter1xxHeadersCallback(Filter1xxHeadersStatus status) {
114:   ASSERT(parent_.state_.has_1xx_headers_);
115:   ASSERT(!continued_1xx_headers_);
116:   ASSERT(canIterate());
117: 
118:   switch (status) {
119:   case Filter1xxHeadersStatus::Continue:
120:     continued_1xx_headers_ = true;
121:     return true;
122:   case Filter1xxHeadersStatus::StopIteration:
123:     iteration_state_ = IterationState::StopSingleIteration;
124:     return false;
125:   }
126: 
127:   PANIC_DUE_TO_CORRUPT_ENUM;
128: }
