130: bool ActiveStreamFilterBase::commonHandleAfterHeadersCallback(FilterHeadersStatus status,
131:                                                               bool& end_stream) {
132:   ASSERT(!headers_continued_);
133:   ASSERT(canIterate());
134: 
135:   switch (status) {
136:   case FilterHeadersStatus::StopIteration:
137:     iteration_state_ = IterationState::StopSingleIteration;
138:     break;
139:   case FilterHeadersStatus::StopAllIterationAndBuffer:
140:     iteration_state_ = IterationState::StopAllBuffer;
141:     break;
142:   case FilterHeadersStatus::StopAllIterationAndWatermark:
143:     iteration_state_ = IterationState::StopAllWatermark;
144:     break;
145:   case FilterHeadersStatus::ContinueAndDontEndStream:
146:     end_stream = false;
147:     headers_continued_ = true;
148:     ENVOY_STREAM_LOG(debug, "converting to headers and body (body not available yet)", parent_);
149:     break;
150:   case FilterHeadersStatus::Continue:
151:     headers_continued_ = true;
152:     break;
153:   }
154: 
155:   handleMetadataAfterHeadersCallback();
156: 
157:   if (stoppedAll() || status == FilterHeadersStatus::StopIteration) {
158:     return false;
159:   } else {
160:     return true;
161:   }
162: }
