186:       commonHandleBufferData(provided_data);
187:       commonContinue();
188:       return false;
189:     } else {
190:       ASSERT(headers_continued_);
191:     }
192:   } else {
193:     iteration_state_ = IterationState::StopSingleIteration;
194:     if (status == FilterDataStatus::StopIterationAndBuffer ||
195:         status == FilterDataStatus::StopIterationAndWatermark) {
196:       buffer_was_streaming = status == FilterDataStatus::StopIterationAndWatermark;
197:       commonHandleBufferData(provided_data);
198:     } else if (observedEndStream() && !hasTrailers() && !bufferedData() &&
199:                // If the stream is destroyed, no need to handle the data buffer or trailers.
200:                // This can occur if the filter calls sendLocalReply.
