215: bool ActiveStreamFilterBase::commonHandleAfterTrailersCallback(FilterTrailersStatus status) {
216: 
217:   if (status == FilterTrailersStatus::Continue) {
218:     if (iteration_state_ == IterationState::StopSingleIteration) {
219:       commonContinue();
220:       return false;
221:     } else {
222:       ASSERT(headers_continued_);
223:     }
224:   } else if (status == FilterTrailersStatus::StopIteration) {
225:     if (canIterate()) {
226:       iteration_state_ = IterationState::StopSingleIteration;
227:     }
228:     return false;
229:   }
230: 
