638: void FilterManager::decodeData(ActiveStreamDecoderFilter* filter, Buffer::Instance& data,
639:                                bool end_stream,
640:                                FilterIterationStartState filter_iteration_start_state) {
641:   ScopeTrackerScopeState scope(this, dispatcher_);
642:   filter_manager_callbacks_.resetIdleTimer();
643: 
644:   // If a response is complete or a reset has been sent, filters do not care about further body
645:   // data. Just drop it.
646:   if (stopDecoderFilterChain()) {
647:     return;
648:   }
649: 
650:   auto trailers_added_entry = decoder_filters_.end();
651:   const bool trailers_exists_at_start = filter_manager_callbacks_.requestTrailers().has_value();
652:   // Filter iteration may start at the current filter.
653:   StreamDecoderFilters::Iterator entry = commonDecodePrefix(filter, filter_iteration_start_state);
654:   bool terminal_filter_decoded_end_stream = false;
655:   ASSERT(!state_.decoder_filter_chain_complete_ || entry == decoder_filters_.end() ||
656:          (*entry)->end_stream_);
657: 
658:   for (; entry != decoder_filters_.end(); entry++) {
659:     ENVOY_EXECUTION_SCOPE(trackedStream(), &(*entry)->filter_context_);
660:     // If the filter pointed by entry has stopped for all frame types, return now.
661:     if (handleDataIfStopAll(**entry, data, state_.decoder_filters_streaming_)) {
662:       return;
663:     }
664:     // If end_stream_ is marked for a filter, the data is not for this filter and filters after.
665:     //
666:     // In following case, ActiveStreamFilterBase::commonContinue() could be called recursively and
667:     // its doData() is called with wrong data.
668:     //
669:     //  There are 3 decode filters and "wrapper" refers to ActiveStreamFilter object.
670:     //
671:     //  filter0->decodeHeaders(_, true)
672:     //    return STOP
673:     //  filter0->continueDecoding()
674:     //    wrapper0->commonContinue()
675:     //      wrapper0->decodeHeaders(_, _, true)
676:     //        filter1->decodeHeaders(_, true)
677:     //          filter1->addDecodeData()
678:     //          return CONTINUE
679:     //        filter2->decodeHeaders(_, false)
680:     //          return CONTINUE
681:     //        wrapper1->commonContinue() // Detects data is added.
682:     //          wrapper1->doData()
683:     //            wrapper1->decodeData()
684:     //              filter2->decodeData(_, true)
685:     //                 return CONTINUE
686:     //      wrapper0->doData() // This should not be called
687:     //        wrapper0->decodeData()
688:     //          filter1->decodeData(_, true)  // It will cause assertions.
689:     //
690:     // One way to solve this problem is to mark end_stream_ for each filter.
691:     // If a filter is already marked as end_stream_ when decodeData() is called, bails out the
692:     // whole function. If just skip the filter, the codes after the loop will be called with
693:     // wrong data. For encodeData, the response_encoder->encode() will be called.
694:     if ((*entry)->end_stream_) {
695:       return;
696:     }
697:     ASSERT(!(state_.filter_call_state_ & FilterCallState::DecodeData));
698: 
699:     // We check the request_trailers_ pointer here in case addDecodedTrailers
700:     // is called in decodeData during a previous filter invocation, at which point we communicate to
701:     // the current and future filters that the stream has not yet ended.
702:     if (end_stream) {
703:       state_.filter_call_state_ |= FilterCallState::EndOfStream;
704:     }
705: 
706:     recordLatestDataFilter(entry, state_.latest_data_decoding_filter_, decoder_filters_);
707: 
708:     state_.filter_call_state_ |= FilterCallState::DecodeData;
709:     (*entry)->end_stream_ = end_stream && !filter_manager_callbacks_.requestTrailers();
710:     FilterDataStatus status = (*entry)->handle_->decodeData(data, (*entry)->end_stream_);
711:     if ((*entry)->end_stream_) {
712:       (*entry)->handle_->decodeComplete();
713:     }
714:     state_.filter_call_state_ &= ~FilterCallState::DecodeData;
715:     if (end_stream) {
716:       state_.filter_call_state_ &= ~FilterCallState::EndOfStream;
717:     }
718:     ENVOY_STREAM_LOG(trace, "decode data called: filter={} status={}", *this,
719:                      (*entry)->filter_context_.config_name, static_cast<uint64_t>(status));
720:     if (state_.decoder_filter_chain_aborted_) {
721:       executeLocalReplyIfPrepared();
722:       ENVOY_STREAM_LOG(trace, "decodeData filter iteration aborted due to local reply: filter={}",
723:                        *this, (*entry)->filter_context_.config_name);
724:       return;
725:     }
726: 
727:     processNewlyAddedMetadata();
728: 
729:     if (!trailers_exists_at_start && filter_manager_callbacks_.requestTrailers() &&
730:         trailers_added_entry == decoder_filters_.end()) {
731:       end_stream = false;
732:       trailers_added_entry = entry;
733:     }
734: 
735:     // The decoder filter chain is finished here if the following is true:
736:     // 1. the last filter has observed the end_stream AND
737:     // 2. no filter, including the last filter, has injected trailers during header iteration.
738:     //    NOTE: end_stream is set to false above if a filter injected trailers.
739:     // If trailers were injected the end_stream will be processed in the `decodeTrailers()` method
740:     // below.
741:     terminal_filter_decoded_end_stream = end_stream && std::next(entry) == decoder_filters_.end();
742: 
743:     if (!(*entry)->commonHandleAfterDataCallback(status, data, state_.decoder_filters_streaming_) &&
744:         std::next(entry) != decoder_filters_.end()) {
745:       // Stop iteration IFF this is not the last filter. If it is the last filter, continue with
746:       // processing since we need to handle the case where a terminal filter wants to buffer, but
747:       // a previous filter has added trailers.
748:       break;
749:     }
750:   }
751: 
752:   // If trailers were adding during decodeData we need to trigger decodeTrailers in order
753:   // to allow filters to process the trailers.
754:   if (trailers_added_entry != decoder_filters_.end()) {
755:     decodeTrailers(trailers_added_entry->get(), *filter_manager_callbacks_.requestTrailers());
756:   }
757: 
758:   if (end_stream) {
759:     disarmRequestTimeout();
760:   }
761:   maybeEndDecode(terminal_filter_decoded_end_stream);
762: }
