775:       (state_.filter_call_state_ & FilterCallState::DecodeHeaders) ||
776:       (state_.filter_call_state_ & FilterCallState::DecodeData) ||
777:       ((state_.filter_call_state_ & FilterCallState::DecodeTrailers) && !filter.canIterate())) {
