843: void FilterManager::decodeMetadata(ActiveStreamDecoderFilter* filter, MetadataMap& metadata_map) {
844:   ScopeTrackerScopeState scope(&*this, dispatcher_);
845:   filter_manager_callbacks_.resetIdleTimer();
846: 
847:   // Filter iteration may start at the current filter.
848:   StreamDecoderFilters::Iterator entry =
849:       commonDecodePrefix(filter, FilterIterationStartState::CanStartFromCurrent);
850: 
851:   ASSERT(!(state_.filter_call_state_ & FilterCallState::DecodeMetadata));
852: 
853:   for (; entry != decoder_filters_.end(); entry++) {
854:     ENVOY_EXECUTION_SCOPE(trackedStream(), &(*entry)->filter_context_);
855:     // If the filter pointed by entry has stopped for all frame type, stores metadata and returns.
856:     // If the filter pointed by entry hasn't returned from decodeHeaders, stores newly added
857:     // metadata in case decodeHeaders returns StopAllIteration. The latter can happen when headers
858:     // callbacks generate new metadata.
859:     if (!(*entry)->processed_headers_ || (*entry)->stoppedAll()) {
860:       Http::MetadataMapPtr metadata_map_ptr = std::make_unique<Http::MetadataMap>(metadata_map);
861:       (*entry)->getSavedRequestMetadata()->emplace_back(std::move(metadata_map_ptr));
862:       return;
863:     }
864:     state_.filter_call_state_ |= FilterCallState::DecodeMetadata;
865:     FilterMetadataStatus status = (*entry)->handle_->decodeMetadata(metadata_map);
866:     state_.filter_call_state_ &= ~FilterCallState::DecodeMetadata;
867: 
868:     ENVOY_STREAM_LOG(trace, "decode metadata called: filter={} status={}, metadata: {}", *this,
869:                      (*entry)->filter_context_.config_name, static_cast<uint64_t>(status),
870:                      metadata_map);
871:     if (state_.decoder_filter_chain_aborted_) {
872:       // If the decoder filter chain has been aborted, then either:
873:       // 1. This filter has sent a local reply or GoAway from decode metadata.
874:       // 2. This filter is the terminal http filter, and an upstream HTTP filter has sent a local
875:       // reply.
876:       ASSERT((status == FilterMetadataStatus::StopIterationForLocalReply) ||
877:              (std::next(entry) == decoder_filters_.end()));
878:       executeLocalReplyIfPrepared();
879:       ENVOY_STREAM_LOG(trace,
880:                        "decodeMetadata filter iteration aborted due to local reply: filter={}",
881:                        *this, (*entry)->filter_context_.config_name);
882:       return;
883:     }
884: 
885:     // Add the processed metadata to the next entry.
886:     if (status == FilterMetadataStatus::ContinueAll && !(*entry)->canIterate()) {
887:       if (std::next(entry) != decoder_filters_.end()) {
888:         (*std::next(entry))
889:             ->getSavedRequestMetadata()
890:             ->emplace_back(std::make_unique<MetadataMap>(metadata_map));
891:       }
892:       (*entry)->commonContinue();
893:       return;
894:     }
895:   }
896: }
