935: FilterManager::commonDecodePrefix(ActiveStreamDecoderFilter* filter,
936:                                   FilterIterationStartState filter_iteration_start_state) {
937:   if (!filter) {
938:     return decoder_filters_.begin();
939:   }
940:   if (filter_iteration_start_state == FilterIterationStartState::CanStartFromCurrent &&
941:       (*(filter->entry()))->iterate_from_current_filter_) {
942:     // The filter iteration has been stopped for all frame types, and now the iteration continues.
943:     // The current filter's callback function has not been called. Call it now.
944:     return filter->entry();
945:   }
946:   return std::next(filter->entry());
947: }
