949: void DownstreamFilterManager::onLocalReply(StreamFilterBase::LocalReplyData& data) {
950:   state_.under_on_local_reply_ = true;
951:   filter_manager_callbacks_.onLocalReply(data.code_);
952: 
953:   for (auto entry : filters_) {
954:     if (entry->onLocalReply(data) == LocalErrorStatus::ContinueAndResetStream) {
955:       data.reset_imminent_ = true;
956:     }
957:   }
958:   state_.under_on_local_reply_ = false;
959: }
