961: void DownstreamFilterManager::sendLocalReply(
962:     Code code, absl::string_view body,
963:     const std::function<void(ResponseHeaderMap& headers)>& modify_headers,
964:     const absl::optional<Grpc::Status::GrpcStatus> grpc_status, absl::string_view details) {
965:   ASSERT(!state_.under_on_local_reply_);
966:   const bool is_head_request = state_.is_head_request_;
967:   const bool is_grpc_request = state_.is_grpc_request_;
968: 
969:   // Stop filter chain iteration if local reply was sent while filter decoding or encoding callbacks
970:   // are running.
971:   if (state_.filter_call_state_ & FilterCallState::IsDecodingMask) {
972:     state_.decoder_filter_chain_aborted_ = true;
973:   } else if (state_.filter_call_state_ & FilterCallState::IsEncodingMask) {
974:     state_.encoder_filter_chain_aborted_ = true;
975:   }
