1225: void FilterManager::encodeHeaders(ActiveStreamEncoderFilter* filter, ResponseHeaderMap& headers,
1226:                                   bool end_stream) {
1227:   // See encodeHeaders() comments in envoy/http/filter.h for why the 1xx precondition holds.
1228:   ASSERT(!CodeUtility::is1xx(Utility::getResponseStatus(headers)) ||
1229:          Utility::getResponseStatus(headers) == enumToInt(Http::Code::SwitchingProtocols));
1230:   filter_manager_callbacks_.resetIdleTimer();
1231:   disarmRequestTimeout();
1232: 
1233:   // Headers filter iteration should always start with the next filter if available.
1234:   StreamEncoderFilters::Iterator entry =
1235:       commonEncodePrefix(filter, end_stream, FilterIterationStartState::AlwaysStartFromNext);
1236:   StreamEncoderFilters::Iterator continue_data_entry = encoder_filters_.end();
1237: 
1238:   for (; entry != encoder_filters_.end(); entry++) {
1239:     ENVOY_EXECUTION_SCOPE(trackedStream(), &(*entry)->filter_context_);
1240:     ASSERT(!(state_.filter_call_state_ & FilterCallState::EncodeHeaders));
1241:     state_.filter_call_state_ |= FilterCallState::EncodeHeaders;
1242:     (*entry)->end_stream_ = (end_stream && continue_data_entry == encoder_filters_.end());
1243:     if ((*entry)->end_stream_) {
1244:       state_.filter_call_state_ |= FilterCallState::EndOfStream;
1245:     }
1246:     FilterHeadersStatus status = (*entry)->handle_->encodeHeaders(headers, (*entry)->end_stream_);
1247:     if (state_.encoder_filter_chain_aborted_) {
1248:       ENVOY_STREAM_LOG(trace,
1249:                        "encodeHeaders filter iteration aborted due to local reply: filter={}",
1250:                        *this, (*entry)->filter_context_.config_name);
1251:       status = FilterHeadersStatus::StopIteration;
1252:     }
1253: 
1254:     ASSERT(!(status == FilterHeadersStatus::ContinueAndDontEndStream && !(*entry)->end_stream_),
1255:            "Filters should not return FilterHeadersStatus::ContinueAndDontEndStream from "
1256:            "encodeHeaders when end_stream is already false");
1257: 
1258:     state_.filter_call_state_ &= ~FilterCallState::EncodeHeaders;
1259:     if ((*entry)->end_stream_) {
1260:       state_.filter_call_state_ &= ~FilterCallState::EndOfStream;
1261:     }
1262:     ENVOY_STREAM_LOG(trace, "encode headers called: filter={} status={}", *this,
1263:                      (*entry)->filter_context_.config_name, static_cast<uint64_t>(status));
1264: 
1265:     (*entry)->processed_headers_ = true;
1266: 
1267:     const auto continue_iteration = (*entry)->commonHandleAfterHeadersCallback(status, end_stream);
1268: 
1269:     // If this filter ended the stream, encodeComplete() should be called for it.
1270:     if ((*entry)->end_stream_) {
