1316: void FilterManager::encodeMetadata(ActiveStreamEncoderFilter* filter,
1317:                                    MetadataMapPtr&& metadata_map_ptr) {
1318:   filter_manager_callbacks_.resetIdleTimer();
1319: 
1320:   StreamEncoderFilters::Iterator entry =
1321:       commonEncodePrefix(filter, false, FilterIterationStartState::CanStartFromCurrent);
1322: 
1323:   for (; entry != encoder_filters_.end(); entry++) {
1324:     ENVOY_EXECUTION_SCOPE(trackedStream(), &(*entry)->filter_context_);
1325:     // If the filter pointed by entry has stopped for all frame type, stores metadata and returns.
1326:     // If the filter pointed by entry hasn't returned from encodeHeaders, stores newly added
1327:     // metadata in case encodeHeaders returns StopAllIteration. The latter can happen when headers
1328:     // callbacks generate new metadata.
1329:     if (!(*entry)->processed_headers_ || (*entry)->stoppedAll()) {
1330:       (*entry)->getSavedResponseMetadata()->emplace_back(std::move(metadata_map_ptr));
1331:       return;
1332:     }
1333: 
1334:     state_.filter_call_state_ |= FilterCallState::EncodeMetadata;
1335: 
1336:     FilterMetadataStatus status = (*entry)->handle_->encodeMetadata(*metadata_map_ptr);
1337: 
1338:     state_.filter_call_state_ &= ~FilterCallState::EncodeMetadata;
1339: 
1340:     ENVOY_STREAM_LOG(trace, "encode metadata called: filter={} status={} metadata={}", *this,
1341:                      (*entry)->filter_context_.config_name, static_cast<uint64_t>(status),
1342:                      *metadata_map_ptr);
1343: 
1344:     if (status == FilterMetadataStatus::StopIterationForLocalReply) {
1345:       // In case of a local reply, we do not continue encoding metadata. Metadata is not sent on to
1346:       // the client.
1347:       return;
1348:     }
1349: 
1350:     if (status == FilterMetadataStatus::ContinueAll && !(*entry)->canIterate()) {
1351:       if (std::next(entry) != encoder_filters_.end()) {
1352:         (*std::next(entry))->getSavedResponseMetadata()->emplace_back(std::move(metadata_map_ptr));
1353:       } else {
1354:         filter_manager_callbacks_.encodeMetadata(std::move(metadata_map_ptr));
1355:       }
1356:       (*entry)->commonContinue();
1357:       return;
1358:     }
1359:   }
1360:   // TODO(soya3129): update stats with metadata.
1361: 
1362:   // Now encode metadata via the codec.
1363:   if (!metadata_map_ptr->empty()) {
1364:     filter_manager_callbacks_.encodeMetadata(std::move(metadata_map_ptr));
